60	/// Result of parsing positional `..` notation.
61	///
62	/// Counts are `Some(0)` for closed sides and `None` for open (dotted) sides.
63	/// Open sides become unlimited unless a positional count is applied later.
64	#[derive(Debug, Clone, PartialEq, Eq)]
65	pub struct DotSpec {
66	    /// The bare revision (without `..`).
67	    pub rev: String,
68	    /// Descendant count: `None` = open (dotted), `Some(0)` = closed.
69	    pub desc_count: Option<usize>,
70	    /// Ancestor count: `None` = open (dotted), `Some(0)` = closed.
71	    pub anc_count: Option<usize>,
72	}
73	
74	/// Parse a positional REV string for `..` notation.
75	///
76	/// Returns the bare revision with open/closed counts per side.
77	/// `None` means the side had dots (open for expansion);
78	/// `Some(0)` means no dots on that side (closed).
79	/// Actual counts are applied later from positional args.
80	pub fn parse_dot_rev(rev: &str) -> DotSpec {
81	    if let Some(inner) = rev.strip_prefix("..").and_then(|s| s.strip_suffix("..")) {
82	        DotSpec {
83	            rev: inner.to_string(),
84	            desc_count: None,
85	            anc_count: None,
86	        }
87	    } else if let Some(inner) = rev.strip_prefix("..") {
88	        DotSpec {
89	            rev: inner.to_string(),
90	            desc_count: None,
91	            anc_count: Some(0),
92	        }
93	    } else if let Some(inner) = rev.strip_suffix("..") {
94	        DotSpec {
95	            rev: inner.to_string(),
96	            desc_count: Some(0),
97	            anc_count: None,
98	        }
99	    } else {
100	        DotSpec {
101	            rev: rev.to_string(),
102	            desc_count: Some(0),
103	            anc_count: Some(0),
104	        }
105	    }
106	}
107	
108	/// Resolve positional and flag args into a `DotSpec` ready for `collect_ids`.
109	///
110	/// Handles: dot notation parsing, flag vs positional precedence,
111	/// count-means-total semantics (subtracts 1 for anchor).
112	pub fn resolve_spec(
113	    pos_rev: Option<&str>,
114	    pos_count: Option<usize>,
115	    flag_rev: &str,
116	    flag_limit: Option<usize>,
117	    default_rev: &str,
118	) -> DotSpec {
119	    let flag_rev_set = flag_rev != default_rev;
120	    let rev_str = if flag_rev_set {
121	        flag_rev
122	    } else {
123	        pos_rev.unwrap_or(default_rev)
124	    };
125	    let mut spec = parse_dot_rev(rev_str);
126	
127	    let count = if flag_limit.is_some() {
128	        flag_limit
129	    } else {
130	        pos_count
131	    };
132	
133	    if let Some(c) = count {
134	        let n = c.saturating_sub(1);
135	        let both_open = spec.desc_count.is_none() && spec.anc_count.is_none();
136	        if both_open {
137	            // Split budget across both sides: ancestors get the extra
138	            let desc_n = n / 2;
139	            let anc_n = n - desc_n;
140	            spec.desc_count = Some(desc_n);
141	            spec.anc_count = Some(anc_n);
142	        } else {
143	            if spec.desc_count.is_none() {
144	                spec.desc_count = Some(n);
145	            }
146	            if spec.anc_count.is_none() {
147	                spec.anc_count = Some(n);
148	            }
149	            // bare `x 5` → treat as `x.. 5` (ancestors)
150	            if spec.desc_count == Some(0) && spec.anc_count == Some(0) {
151	                spec.anc_count = Some(n);
152	            }
153	        }
154	    }
155	
156	    spec
157	}
