159	/// Wrap text in ANSI bold escape codes.
160	pub fn bold(s: &str) -> String {
161	    format!("\x1b[1m{s}\x1b[0m")
162	}
163	
164	/// Bold only the first line of a multi-line string.
165	pub fn bold_first_line(s: &str) -> String {
166	    if let Some(pos) = s.find('\n') {
167	        format!("\x1b[1m{}\x1b[0m{}", &s[..pos], &s[pos..])
168	    } else {
169	        bold(s)
170	    }
171	}
